import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { useQuery, gql } from '@apollo/client';

const GET_POSTS = gql`
  query GetPosts {
    posts {
      nodes {
        id
        title
        excerpt
        date
        slug
        categories {
          nodes {
            name
          }
        }
      }
    }
  }
`;

function Blog() {
  const { loading, error, data } = useQuery(GET_POSTS);
  const [categActive, setCategActive] = useState('Tous');
  const categories = ['Tous', 'Cybersécurité', 'Réseaux', 'Linux', 'Windows'];

  const articlesWordPress = data?.posts?.nodes || [];

  const articlesFiltres = categActive === 'Tous'
    ? articlesWordPress
    : articlesWordPress.filter(a =>
        a.categories.nodes.some(c => c.name === categActive)
      );

  return (
    <div style={{ background: '#000000', minHeight: '100vh', paddingTop: '100px' }}>

      {/* HEADER */}
      <motion.section
        initial={{ opacity: 0, y: -30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
        style={{
          textAlign: 'center', padding: '60px 20px',
          background: 'radial-gradient(ellipse at center, #0a1a0a 0%, #000000 70%)',
          borderBottom: '2px solid #00aa00'
        }}
      >
        <h1 style={{ fontSize: '48px', color: '#ffd700', letterSpacing: '4px', marginBottom: '15px' }}>Blog</h1>
        <p style={{ color: '#aaaaaa', fontSize: '18px', maxWidth: '600px', margin: '0 auto' }}>
          Je partage mes expériences, apprentissages et projets dans le monde des réseaux, systèmes et cybersécurité.
        </p>
      </motion.section>

      {/* FILTRES */}
      <section style={{ padding: '40px 50px', textAlign: 'center' }}>
        <div style={{ display: 'flex', justifyContent: 'center', gap: '15px', flexWrap: 'wrap' }}>
          {categories.map(cat => (
            <button key={cat} onClick={() => setCategActive(cat)} style={{
              background: categActive === cat ? '#00aa00' : 'transparent',
              color: categActive === cat ? '#ffffff' : '#aaaaaa',
              border: '1px solid #00aa00', padding: '8px 20px',
              borderRadius: '20px', cursor: 'pointer', fontSize: '14px', transition: 'all 0.3s'
            }}>
              {cat}
            </button>
          ))}
        </div>
      </section>

      {/* ARTICLES */}
      <section style={{ padding: '20px 50px 80px', maxWidth: '1200px', margin: '0 auto' }}>

        {/* CHARGEMENT */}
        {loading && (
          <div style={{ textAlign: 'center', padding: '60px' }}>
            <motion.div
              animate={{ rotate: 360 }}
              transition={{ duration: 1, repeat: Infinity, ease: 'linear' }}
              style={{ width: '50px', height: '50px', border: '4px solid #00aa00', borderTop: '4px solid transparent', borderRadius: '50%', margin: '0 auto' }}
            />
            <p style={{ color: '#aaaaaa', marginTop: '20px' }}>Chargement des articles...</p>
          </div>
        )}

        {/* ERREUR */}
        {error && (
          <div style={{ textAlign: 'center', padding: '60px' }}>
            <p style={{ color: '#ff4444', fontSize: '16px' }}>Impossible de charger les articles.</p>
          </div>
        )}

        {/* ARTICLES WORDPRESS */}
        {!loading && !error && (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
            gap: '30px'
          }}>
            {articlesFiltres.length === 0 ? (
              <div style={{ textAlign: 'center', gridColumn: '1/-1', padding: '60px' }}>
                <p style={{ color: '#aaaaaa', fontSize: '18px' }}>Aucun article dans cette catégorie pour l'instant.</p>
                <p style={{ color: '#555555', fontSize: '14px', marginTop: '10px' }}>Revenez bientôt !</p>
              </div>
            ) : (
              articlesFiltres.map((article, index) => (
                <motion.div
                  key={article.id}
                  initial={{ opacity: 0, y: 30 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  whileHover={{ scale: 1.03, boxShadow: '0 0 25px rgba(0,170,0,0.3)' }}
                  transition={{ duration: 0.4, delay: index * 0.1 }}
                  style={{
                    background: '#0a0a0a', border: '1px solid #00aa00',
                    borderRadius: '15px', padding: '30px', cursor: 'pointer'
                  }}
                >
                  <div style={{ display: 'flex', gap: '10px', marginBottom: '12px', flexWrap: 'wrap' }}>
                    {article.categories.nodes.map(cat => (
                      <span key={cat.name} style={{
                        background: '#00aa00', color: '#ffffff',
                        padding: '3px 12px', borderRadius: '12px', fontSize: '12px'
                      }}>
                        {cat.name}
                      </span>
                    ))}
                  </div>
                  <h3 style={{ color: '#ffd700', fontSize: '18px', marginBottom: '12px', lineHeight: '1.4' }}>
                    {article.title}
                  </h3>
                  <div
                    style={{ color: '#aaaaaa', fontSize: '14px', lineHeight: '1.7', marginBottom: '20px' }}
                    dangerouslySetInnerHTML={{ __html: article.excerpt }}
                  />
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <span style={{ color: '#555555', fontSize: '12px' }}>
                      {new Date(article.date).toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' })}
                    </span>
                    <a href={`https://revesyndie.com/${article.slug}`} target="_blank" rel="noreferrer" style={{
                      background: 'transparent', color: '#00aa00',
                      border: '1px solid #00aa00', padding: '6px 18px',
                      borderRadius: '15px', textDecoration: 'none', fontSize: '13px'
                    }}>
                      Lire →
                    </a>
                  </div>
                </motion.div>
              ))
            )}
          </div>
        )}
      </section>
    </div>
  );
}

export default Blog;
